const { runSearchAgent } = require('/opt/node_modules/recon-multiagent/dist/search_agent.js');
const { loadDomainPolicy } = require('/opt/node_modules/recon-multiagent/dist/domain_policy.js');

const body = $input.first().json;
const runId = body.run_id;
const brief = body.brief;

if (!runId || !brief) {
  return [{ json: { statusCode: 400, body: { status: 'missing_run_id_or_brief' } } }];
}

const policy = loadDomainPolicy('/opt/node_modules/recon-multiagent/config/domain_policy.json');

const result = await runSearchAgent(runId, brief, {
  baseUrl: $env.DEEPINFRA_BASE_URL,
  apiKey: $env.DEEPINFRA_API_KEY,
  model: $env.MODEL_NAME ?? 'google/gemma-4-26B-A4B-it',
  searchOpts: {
    apiKey: $env.BRAVE_API_KEY,
    count: $env.SEARCH_COUNT ?? 10,
    timeoutMs: $env.SEARCH_TIMEOUT_MS ?? 10000,
    maxRetries: 3,
  },
  fetchOpts: {
    maxBytes: $env.MAX_FETCH_BYTES ?? 1048576,
    timeoutMs: $env.FETCH_TIMEOUT_MS ?? 15000,
    allowlist: policy.allowlist,
    denylist: policy.denylist.concat(policy.knownMalicious),
    denyPrivate: policy.denyPrivate,
  },
  budgets: {
    max_queries_per_run: Number($env.MAX_QUERIES ?? 20),
    max_fetches_per_run: Number($env.MAX_FETCHES ?? 30),
    max_fetch_bytes: Number($env.MAX_FETCH_BYTES ?? 1048576),
  },
  temperature: 0,
});

return [{ json: { statusCode: 200, body: { status: result.stoppedBecause === 'error' ? 'failed' : 'completed', run_id: runId, ...result } } }];
